package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithHeaderComments_Null() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments((Object[]) null);
        assertNotNull(result);
        assertNull(result.getHeaderComments());
        // ensure original unchanged
        assertNull(format.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_Empty() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments(new Object[0]);
        assertNotNull(result);
        assertNotNull(result.getHeaderComments());
        assertEquals(0, result.getHeaderComments().length);
        // original unchanged
        assertNull(format.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_SingleString() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments(new Object[] { "comment1" });
        assertNotNull(result);
        assertArrayEquals(new String[] {"comment1"}, result.getHeaderComments());
        // original unchanged
        assertNull(format.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_MultipleStrings() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments(new Object[] { "comment1", "comment2", "comment3" });
        assertNotNull(result);
        assertArrayEquals(new String[] {"comment1", "comment2", "comment3"}, result.getHeaderComments());
        // original unchanged
        assertNull(format.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_MixedTypes() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments(new Object[] { "string", 123, true, null });
        assertNotNull(result);
        assertArrayEquals(new String[] {"string", "123", "true", "null"}, result.getHeaderComments());
        // original unchanged
        assertNull(format.getHeaderComments());
    }
}
